	timer := prometheus.NewTimer(prometheus.ObserverFunc(func(v float64) {
		// Observe the duration with specific labels, including status.
		requestDuration.With(prometheus.Labels{
			"user_id":    userID,
			"request_id": requestID,
			"endpoint":   endpoint,
			"status":     "success", // For simplicity, assume all requests are successful in this example.
		}).Observe(v)
	}))
	defer timer.ObserveDuration() // Ensures the duration is recorded when the function exits.

	// Simulate work with a random duration to make the histogram more illustrative.
	minDuration := 50 * time.Millisecond
	maxDuration := 500 * time.Millisecond
	randomDuration := minDuration + time.Duration(randomSource.Float64()*float64(maxDuration-minDuration))
