	// Increment the total request counter, marking the request as successful.
	requestTotal.With(prometheus.Labels{
		"user_id":    userID,
		"request_id": requestID,
		"endpoint":   endpoint,
		"status":     "success",
	}).Inc()

	// Respond to the client.
	fmt.Fprintf(w, "Request processed: UserID=%s, RequestID=%s, Endpoint=%s\n", userID, requestID, endpoint)
